const CITY_DB_MAP = {}
CITY_DB.forEach(c => { CITY_DB_MAP[c.id] = c })

function normalize(s) { return (s || '').toLowerCase().trim() }

function searchCities(q) {
  if (!q) return []
  const qq = normalize(q)
  return CITY_DB.filter(c => {
    return normalize(c.name).includes(qq)
        || normalize(c.nameEn).includes(qq)
        || normalize(c.country).includes(qq)
        || normalize(c.id).includes(qq)
        || (c.aliases || []).some(a => normalize(a).includes(qq))
  }).slice(0, 30)
}

module.exports = {
  CITY_DB,
  CITY_DB_MAP,
  searchCities
}
